from imodels import FIGSClassifier
model = FIGSClassifier(max_rules=12)
model.fit(X_train, y_train)

total_splits = model.complexity_  # total rules/splits
n_trees = len(model.trees_)

# Average path length - traverse trees
def avg_path_length(model, X):
    depths = []
    for tree in model.trees_:
        for sample in X:
            depth = 0
            node = tree
            while hasattr(node, 'feature'):
                depth += 1
                if sample[node.feature] <= node.threshold:
                    node = node.left
                else:
                    node = node.right
            depths.append(depth)
    return np.mean(depths)

