# Oblique tree split arity
def compute_split_arity(tree_nodes):
    arities = []
    for node in tree_nodes:
        if node.is_split:
            n_nonzero = np.count_nonzero(node.coefficients)
            arities.append(n_nonzero)
    return {
        'mean_arity': np.mean(arities),
        'max_arity': np.max(arities),
        'min_arity': np.min(arities)
    }
